const items = $input.all().map(i => i.json);
const properties = [];
const texts = [];
const today = new Date().toISOString();

// Parsea "agente: X" de la descripción (última aparición), normaliza (minúsculas, sin
// acentos, sin puntuación). Devuelve el texto normalizado o null. La resolución a un
// calendar_id concreto la hace la reserva contra la tabla `agents` (single source).
function parseAgent(desc) {
  if (!desc) return null;
  const matches = [...String(desc).matchAll(/agente?\s*:\s*([^\n\r.;,]+)/gi)]; // casa 'Agent:' (EN) y 'agente:' (ES)
  if (!matches.length) return null;
  const norm = matches[matches.length - 1][1]
    .toLowerCase()
    .normalize('NFD').replace(/[̀-ͯ]/g, '')
    .replace(/[^a-z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  return norm || null;
}

// Traduce el propertyType de Idealista al vocabulario del select Kommo "Tipo vivienda"
// (1373283): piso | atico | duplex | chalet | local-oficina | otro. Normalizado para
// casar directo contra lead_preferences.tipo en match_pairs().
function mapType(it) {
  const pt = String(it.propertyType || '').toLowerCase();
  let dt = it.detailedType;
  if (typeof dt === 'string') { try { dt = JSON.parse(dt); } catch (e) { dt = {}; } }
  dt = dt || {};
  const typo = String(dt.typology || '').toLowerCase();
  const sub  = String(dt.subTypology || '').toLowerCase();
  if (pt === 'penthouse' || sub === 'penthouse') return 'atico';
  if (pt === 'duplex'    || sub === 'duplex')    return 'duplex';
  if (pt === 'chalet'    || typo === 'chalet'    ||
      ['semidetachedhouse','independanthouse','independenthouse','terracedhouse','countryhouse'].includes(sub)) return 'chalet';
  if (pt === 'flat' || typo === 'flat' || pt === 'studio' || sub === 'studio') return 'piso';
  if (['premise','office','commercial'].includes(pt)) return 'local-oficina';
  return 'otro';
}

for (const it of items) {
  const url = it.url || '';
  const m = url.match(/\/inmueble\/(\d+)\//);
  if (!m) continue;
  const idealista_id = m[1];

  const text = [
    it.address || '',
    it.municipality || '',
    it.province || '',
    it.description || ''
  ].filter(Boolean).join(' . ').slice(0, 8000);

  properties.push({
    idealista_id,
    url,
    thumbnail: it.thumbnail || null,
    price: it.price ?? null,
    address: it.address || null,
    municipality: it.municipality || null,
    province: it.province || null,
    description: it.description || null,
    rooms: it.rooms ?? null,
    bathrooms: it.bathrooms ?? null,
    size_m2: it.size ?? null,
    agent: parseAgent(it.description),
    property_type: mapType(it),
    status: 'active',
    last_seen_at: today,
    raw: it
  });
  texts.push(text);
}

return [{ json: { properties, texts, sweep_cutoff: today } }];

const embResp = $input.first().json;
const prepared = $('Prepare Items').first().json;
const properties = prepared.properties;
const sweep_cutoff = prepared.sweep_cutoff;

if (!embResp.data || embResp.data.length !== properties.length) {
  throw new Error('Embedding count mismatch: ' + (embResp.data?.length ?? 0) + ' vs ' + properties.length);
}

const sorted = [...embResp.data].sort((a, b) => a.index - b.index);
const enriched = properties.map((p, i) => ({
  ...p,
  embedding: sorted[i].embedding
}));

return [{ json: { properties: enriched, sweep_cutoff } }];

const input = $input.all();
const arr = (input.length === 1 && Array.isArray(input[0].json))
  ? input[0].json
  : input.map(i => i.json);

const tipoMap = {
  flat:'Piso', house:'Casa', chalet:'Chalet', duplex:'Dúplex',
  penthouse:'Ático', studio:'Estudio', premise:'Local',
  office:'Oficina', garage:'Garaje', land:'Terreno'
};

return arr.map(p => {
  const raw = p.raw || {};
  const tipoRaw = raw.propertyType || raw.typology || raw.property_type || '';
  const tipo = tipoMap[tipoRaw] || tipoRaw || '';
  const foto = p.thumbnail ? `=IMAGE("${p.thumbnail}")` : '';
  const precio = p.price ? `€${Number(p.price).toLocaleString('es-ES')}` : '';
  const actualizado = p.last_seen_at ? p.last_seen_at.split('T')[0] : '';
  const desc = p.description || '';

  // Galería: top 10 URLs de la primera ráfaga de imágenes de Apify.
  const imagesSource = Array.isArray(raw?.multimedia?.images)
    ? raw.multimedia.images.map(x => x && x.url).filter(Boolean).slice(0, 10)
    : [];

  return { json: {
    Foto: foto,
    Referencia: p.idealista_id || '',
    Agente: p.agent || '',
    Tipo: tipo,
    Direccion: p.address || '',
    Municipio: p.municipality || '',
    Precio: precio,
    m2: p.size_m2 || '',
    Hab: p.rooms || '',
    Banos: p.bathrooms || '',
    URL: p.url || '',
    Descripcion: desc,
    Actualizado: actualizado,
    thumbnail_url: p.thumbnail || '',
    thumbnail_hosted: p.thumbnail_hosted || '',
    imagesSource: imagesSource
  }};
});

const original = $('Split Properties').item.json;
if (original.thumbnail_hosted) {
  return { json: { ...original } };
}
const uploadResult = $input.item.json;
const uploadOk = !uploadResult.error && original.thumbnail_url;
const thumbnailHosted = uploadOk
  ? 'https://supabase-simarro.agentesia.madrid/storage/v1/object/public/thumbnails/' + original.Referencia + '.jpg'
  : '';
return { json: { ...original, thumbnail_hosted: thumbnailHosted } };

